def restore_workspace_from_yaml(state_yaml: str) -> dict:
    """Restore workspace state from a YAML string.

    This function parses a YAML string representing a workspace state
    and returns it as a dictionary.

    Args:
        state_yaml: A string containing YAML-formatted workspace state.

    Returns:
        A dictionary representing the restored workspace state.

    Raises:
        ValueError: If the YAML string is invalid or cannot be parsed.
    """
    if not isinstance(state_yaml, str):
        raise ValueError("state_yaml must be a string")

    if not state_yaml:
        return {}

    try:
        # Using safe_load for security - only constructs simple Python objects
        # and prevents arbitrary code execution vulnerabilities
        state = yaml.safe_load(state_yaml)

        if state is None:
            return {}

        if not isinstance(state, dict):
            raise ValueError("YAML content must represent a dictionary")

        return state

    except yaml.YAMLError as e:
        raise ValueError(f"Invalid YAML format: {e}") from e
    except Exception as e:
        raise ValueError(f"Failed to restore workspace state: {e}") from e

